import { Layer } from '@vis.gl/react-maplibre';

import { _getCanvasColor as getCanvasColor } from '@dynatrace/strato-components/charts';

import { useSizeInterpolation } from './hooks/use-size-interpolation.js';
import { addOutlineSize } from './utils/add-outline-size.js';
import { buildOutlineStickToDistanceExpression } from './utils/build-stick-to-distance-expressions.js';
import {
  ACTIVE_COLOR,
  BUBBLE_OUTLINE_STROKE,
  DEFAULT_RADIUS_EXPRESSION,
} from '../../constants.js';

const DEFAULT_OUTLINE_RADIUS_EXPRESSION = addOutlineSize(
  DEFAULT_RADIUS_EXPRESSION,
);

export const BubbleOutlineLayer = ({
  beforeId,
  source,
}: {
  beforeId: string;
  source: string;
}) => {
  const sizeInterpolation = useSizeInterpolation();

  const outlineRadiusExpression =
    sizeInterpolation === 'fixed'
      ? DEFAULT_OUTLINE_RADIUS_EXPRESSION
      : buildOutlineStickToDistanceExpression();

  return (
    <Layer
      type="circle"
      beforeId={beforeId}
      source={source}
      paint={{
        'circle-radius': outlineRadiusExpression,
        'circle-opacity': 0,
        'circle-stroke-width': BUBBLE_OUTLINE_STROKE,
        'circle-stroke-color': getCanvasColor(ACTIVE_COLOR),
        'circle-stroke-opacity': [
          'case',
          ['boolean', ['feature-state', 'active'], false],
          1,
          0,
        ],
      }}
    />
  );
};
